export async function requireUserSession(event: UseSessionEvent, opts: { statusCode?: number, message?: string } = {}): Promise<UserSessionRequired> {
  const userSession = await getUserSession(event)

  if (!userSession.user) {
    if (isEvent(event)) {
      throw createError({
        statusCode: opts.statusCode || 401,
        message: opts.message || 'Unauthorized',
      })
    }
    else {
      throw new Response(opts.message || 'Unauthorized', {
        status: opts.statusCode || 401,
      })
    }
  }

  return userSession as UserSessionRequired
}

export function defineCachedHandler(
  handler: EventHandler,
  opts: CachedEventHandlerOptions = {}
): EventHandler {
  ensureStorage();
  const ocacheHandler = _defineCachedHandler(handler as any, {
    group: "nitro/handlers",
    onError: defaultOnError,
    toResponse: (value, event) => toResponse(value, event as H3Event),
    createResponse: (body, init) => new FastResponse(body, init),
    handleCacheHeaders: (event, conditions) => handleCacheHeaders(event as H3Event, conditions),
    ...opts,
  });
  return defineHandler((event) => ocacheHandler(event as any));
}

export const useImageProps = <Provider extends keyof ConfiguredImageProviders>(props: BaseImageProps<Provider>) => {
  const $img = useImage()

  const providerOptions = computed(() => ({
    provider: props.provider,
    preset: props.preset,
  }))

  const normalizedAttrs = computed(() => ({
    width: parseSize(props.width),
    height: parseSize(props.height),
    crossorigin: props.crossorigin === true ? 'anonymous' : props.crossorigin || undefined,
    nonce: props.nonce,
  }))

  const imageModifiers = computed(() => {
    return {
      ...props.modifiers,
      width: props.width,
      height: props.height,
      format: props.format,
      quality: props.quality || $img.options.quality,
      background: props.background,
      fit: props.fit,
    } satisfies Partial<ImageModifiers>
  })

  return { providerOptions, normalizedAttrs, imageModifiers }
}

export async function handleState(event: H3Event) {
  const query = getQuery<{ state?: string }>(event)
  // If the state is in the query, get it from the cookie and delete the cookie
  if (query.state) {
    const state = getCookie(event, 'nuxt-auth-state')
    deleteCookie(event, 'nuxt-auth-state')
    return state
  }

  // If the state is not in the query, generate a new state and set it in the cookie
  const state = encodeBase64Url(getRandomBytes(8))
  setCookie(event, 'nuxt-auth-state', state, {
    httpOnly: true,
    secure: !isDevelopment,
    sameSite: 'lax',
    maxAge: OAUTH_COOKIE_MAX_AGE,
    path: '/',
  })
  return state
}

export function addTemplate<T> (_template: NuxtTemplate<T> | string): ResolvedNuxtTemplate<T> {
  const nuxt = useNuxt()

  // Normalize template
  const template = normalizeTemplate(_template)

  // Remove any existing template with the same destination path
  filterInPlace(nuxt.options.build.templates, p => (p.dst || normalizeTemplate(p).dst) !== template.dst)

  try {
    const distDir = distDirURL.toString()
    const { source } = captureStackTrace().find(e => e.source && !e.source.startsWith(distDir)) ?? {}
    if (source) {
      const path = normalize(fileURLToPath(source))
      if (existsSync(path)) {
        template._path = path
      }
    }
  } catch {
    // ignore errors as this is an additive feature
  }

  // Add to templates array
  nuxt.options.build.templates.push(template)

  return template
}

export async function getLocaleMessagesMergedCached(locale: string, loaders: LocaleLoader[] = []) {
  const nuxtApp = useNuxtApp()
  const messages = await Promise.all(loaders.map(async (loader) => {
    const cached = getCachedMessages(loader)
    const messages = cached || (await nuxtApp.runWithContext(() => getLocaleMessages(locale, loader)))

    if (!cached && loader.cache !== false) {
      cacheMessages.set(loader.key, { ttl: Date.now() + __I18N_CACHE_LIFETIME__ * 1000, value: messages })
    }

    return messages
  }))

  const merged: LocaleMessages<DefineLocaleMessage> = {}
  for (const message of messages) {
    deepCopy(message, merged)
  }

  return merged
}

export class StateStore implements NodeSavedStateStore {
  private readonly stateKey = 'oauth-bluesky-state'

  constructor(private event: H3Event) {}

  async get(): Promise<NodeSavedState | undefined> {
    const result = getCookie(this.event, this.stateKey)
    if (!result) return
    return JSON.parse(atob(result))
  }

  async set(key: string, val: NodeSavedState) {
    setCookie(this.event, this.stateKey, btoa(JSON.stringify(val)), {
      path: '/',
      httpOnly: true,
      secure: true,
      sameSite: 'lax',
    })
  }

  async del() {
    deleteCookie(this.event, this.stateKey)
  }
}

export async function validateUserData<T>(
  userBody: WebAuthnUser,
  event: H3Event,
  fn: ValidateUserFunction<T>,
): Promise<T> {
  try {
    const res = await fn(userBody, event)
    if (res === false) {
      throw createUserValidationError()
    }
    if (res === true) {
      return userBody as T
    }
    return res ?? (userBody as T)
  }
  catch (error) {
    throw createUserValidationError(error as Error)
  }
}
// eslint-disable-next-line @typescript-eslint/no-explicit-any
function createUserValidationError(validateError?: any) {
  throw createError({
    status: validateError?.statusCode || 400,
    message: validateError?.message || 'User Validation Error',
    data: validateError,
  })
}

export function resolveNitroPath(
  path: string,
  nitroOptions: Nitro["options"],
  base?: string
): string {
  if (typeof path !== "string") {
    throw new TypeError("Invalid path: " + path);
  }

  // TODO: Skip if no template used
  path = _compilePathTemplate(path)(nitroOptions);
  for (const base in nitroOptions.alias) {
    if (path.startsWith(base)) {
      path = nitroOptions.alias[base] + path.slice(base.length);
    }
  }

  // eslint-disable-next-line no-control-regex
  if (/^[#\u0000]/.test(path)) {
    return path;
  }

  return resolve(base || nitroOptions.rootDir, path);
}

const canPrerender = (route = "/") => {
  // Skip if route is already generated or skipped
  if (generatedRoutes.has(route) || skippedRoutes.has(route)) {
    return false;
  }

  // Check for explicitly ignored routes
  if (nitro.options.prerender.ignore) {
    for (const pattern of nitro.options.prerender.ignore) {
      if (matchesIgnorePattern(route, pattern)) {
        return false;
      }
    }
  }

  if (publicAssetBases.some((base) => route.startsWith(base))) {
    return false;
  }

  if (scannedPublicAssets.has(route)) {
    return false;
  }

  // Check for route rules explicitly disabling prerender
  if (_getRouteRules(route).prerender === false) {
    return false;
  }

  return true;
};

export async function generateItemSurround<T extends PageCollectionItemBase>(queryBuilder: CollectionQueryBuilder<T>, path: string, opts?: SurroundOptions<keyof T>) {
  const { before = 1, after = 1, fields = [] } = opts || {}
  const navigation = await generateNavigationTree(queryBuilder, fields)

  const flatData = flattedData(navigation)
  const index = flatData.findIndex(item => item.path === path)
  const beforeItems = index === -1 ? [] : flatData.slice(index - before, index)
  const afterItems = index === -1 ? [] : flatData.slice(index + 1, index + after + 1)

  return [
    ...(Array.from({ length: before }).fill(null).concat(beforeItems).slice(beforeItems.length)),
    ...afterItems.concat(Array.from({ length: after }).fill(null) as typeof afterItems).slice(0, after),
  ] as ContentNavigationItem[]
}

function resolveSource(source: string | CollectionSource | CollectionSource[] | undefined): ResolvedCollectionSource[] | undefined {
  if (!source) {
    return undefined
  }

  if (typeof source === 'string') {
    return [defineLocalSource({ include: source })]
  }

  const sources: CollectionSource[] = Array.isArray(source) ? source : [source]

  return sources.map((source) => {
    if ((source as ResolvedCollectionSource)._resolved) {
      return source as ResolvedCollectionSource
    }

    if (source.repository) {
      return defineGitSource(source)
    }

    return defineLocalSource(source)
  })
}

export async function findPath (paths: string | string[], opts?: ResolvePathOptions, pathType: PathType = 'file'): Promise<string | null> {
  for (const path of toArray(paths)) {
    // TODO: this is for backwards compatibility, remove the `pathType` argument in Nuxt 5
    const type = opts?.type || pathType
    const res = await _resolvePathGranularly(path, {
      ...opts,
      type,
    })

    if (!res.type || res.type !== type) {
      continue
    }

    // Check file system
    if (res.virtual || await existsSensitive(res.path)) {
      return res.path
    }
  }
  return null
}

export function matchLocalized(path: string, locale: string, defaultLocale: string): string | undefined {
  if (path === '') { return }
  const parsed = parsePath(path)
  const resolvedMatch = matcher.resolve(
    { path: parsed.pathname || '/' },
    { path: '/', name: '', matched: [], params: {}, meta: {} },
  )

  if (resolvedMatch.matched.length > 0) {
    const alternate = getI18nPathToI18nPath(resolvedMatch.matched[0]!.path, locale)
    const match = matcher.resolve(
      { params: resolvedMatch.params },
      { path: alternate || '/', name: '', matched: [], params: {}, meta: {} },
    )

    const isPrefixable = prefixable(locale, defaultLocale)
    return formatTrailingSlash(withLeadingSlash(joinURL(isPrefixable ? locale : '', match.path)), true)
  }
}

function getHreflangLinks(options: HeadContext) {
  if (!options.hreflangLinks) { return [] }

  const links: MetaAttrs[] = []
  const localeMap = createLocaleMap(options.locales)
  for (const [language, locale] of localeMap.entries()) {
    const link = getHreflangLink(language, locale, options)
    if (!link) { continue }

    links.push(link)
    if (options.defaultLocale && options.defaultLocale === locale.code && links[0]!.hreflang !== 'x-default') {
      links.unshift(
        strictSeo
          ? { rel: 'alternate', href: link.href!, hreflang: 'x-default' }
          : { [options.key]: 'i18n-xd', rel: 'alternate', href: link.href!, hreflang: 'x-default' },
      )
    }
  }

  return links
}

export function getNitroRouteRules(path: string): Partial<RouteOptions> {
  const { nitro, app } = useRuntimeConfig()

  if (!routeMatcher) {
    routeMatcher = toRouteMatcher(
      createRouter({
        routes: Object.fromEntries(
          Object.entries(nitro?.routeRules || {})
            .map(([path, rules]) => [withoutTrailingSlash(path), rules])
        )
      })
    )
  }

  const options: Partial<RouteOptions> = {}

  const matches = routeMatcher.matchAll(
    withoutBase(withoutTrailingSlash(withoutQuery(path)), app.baseURL)
  ).toReversed()

  for (const match of matches) {
    options.disableServerSideAuth ??= match.auth?.disableServerSideAuth
  }

  return options
}

