export async function refineDatabaseConfig(database: ModuleOptions['database'], opts: { rootDir: string, updateSqliteFileName?: boolean }) {
  if (database.type === 'd1') {
    if (!('bindingName' in database)) {
      // @ts-expect-error bindingName
      database.bindingName = database.binding
    }
  }

  if (database.type === 'sqlite') {
    const path = isAbsolute(database.filename)
      ? database.filename
      : join(opts.rootDir, database.filename)
    await mkdir(dirname(path), { recursive: true }).catch(() => {})

    if (opts.updateSqliteFileName) {
      database.filename = path
    }
  }
}

export async function ensurePackageInstalled(pkg: string) {
  if (!await isPackageInstalled(pkg)) {
    logger.error(`Nuxt Content requires \`${pkg}\` module to operate.`)

    const confirm = await logger.prompt(`Do you want to install \`${pkg}\` package?`, {
      type: 'confirm',
      name: 'confirm',
      initial: true,
    })

    if (!confirm) {
      logger.error(`Nuxt Content requires \`${pkg}\` module to operate. Please install \`${pkg}\` package manually and try again. \`npm install ${pkg}\``)
      process.exit(1)
    }

    await addDependency(pkg, {
      cwd: tryUseNuxt()?.options.rootDir,
    })
  }
}

function setupRouteTracking(timeline: TimelineMetrics, router: Router) {
  // Add initial route event
  if (timeline.options.enabled && router?.currentRoute?.value?.path) {
    const start = timeline.events[0]?.start || Date.now()
    timeline.events.unshift({
      type: 'route',
      from: router.currentRoute.value.path,
      to: router.currentRoute.value.path,
      start,
      end: start,
    })
  }

  let lastRouteEvent: TimelineEventRoute | undefined
  router?.afterEach(() => {
    if (lastRouteEvent && !lastRouteEvent?.end)
      lastRouteEvent.end = Date.now()
  })
  router?.beforeEach((to, from) => {
    if (!timeline.options.enabled)
      return
    lastRouteEvent = {
      type: 'route',
      from: from.path,
      to: to.path,
      start: Date.now(),
    }
    timeline.events.push(lastRouteEvent)
  })
}

function waitForClientInjection(retry = 20, timeout = 300) {
  let lastError: any
  const test = () => {
    try {
      return !!iframe?.contentWindow?.__NUXT_DEVTOOLS_VIEW__
    }
    catch (e) {
      lastError = e
    }
    return false
  }

  if (test())
    return

  return new Promise<void>((resolve, reject) => {
    const interval = setInterval(() => {
      if (test()) {
        clearInterval(interval)
        resolve()
      }
      else if (retry-- <= 0) {
        clearInterval(interval)
        reject(lastError)
      }
    }, timeout)
  })
}

export function matchDomainLocale(locales: LocaleObject[], host: string, pathLocale: string): string | undefined {
  const normalizeDomain = (domain: string = '') => domain.replace(/https?:\/\//, '')
  const matches = locales.filter(
    locale => normalizeDomain(locale.domain) === host || toArray(locale.domains).includes(host),
  )

  if (matches.length <= 1) {
    return matches[0]?.code
  }

  return (
    // match by current path locale
    matches.find(l => l.code === pathLocale)?.code
    // fallback to default locale for the domain
    || matches.find(l => l.defaultForDomains?.includes(host) ?? l.domainDefault)?.code
  )
}

export function domainFromLocale(
  domainLocales: Record<string, { domain: string | undefined }>,
  url: { host: string, protocol: string },
  locale: string,
): string | undefined {
  const lang = normalizedLocales.find(x => x.code === locale)
  // lookup the `differentDomain` origin associated with given locale.
  const domain = domainLocales?.[locale]?.domain || lang?.domain || lang?.domains?.find(v => v === url.host)

  if (!domain) {
    import.meta.dev && console.warn('[nuxt-i18n] Could not find domain name for locale ' + locale)
    return
  }

  if (hasProtocol(domain, { strict: true })) {
    return domain
  }

  return url.protocol + '//' + domain
}

export function createUserLocaleDetector(defaultLocale: string, fallbackLocale: FallbackLocale) {
  return async (event: H3Event, i18nCtx: CoreOptions): Promise<Locale> => {
    const locale = localeDetector!(event, { defaultLocale, fallbackLocale })

    // Merge messages into i18n context which contains unserializable messages from vue-i18n configurations
    const messages = await fetchMessages(locale)
    for (const locale of Object.keys(messages)) {
      i18nCtx.messages![locale] ??= {}
      deepCopy(messages[locale], i18nCtx.messages![locale])
    }

    return locale
  }
}

export default async function installPlugin(nuxt = useNuxt()) {
  if (nuxt.options.builder === '@nuxt/vite-builder') {
    const existsTailwindPlugin = (plugins = nuxt.options.vite.plugins): boolean => !!plugins?.some((plugin) => {
      if (Array.isArray(plugin)) {
        return existsTailwindPlugin(plugin)
      }

      return plugin && 'name' in plugin && plugin.name.startsWith('@tailwindcss/vite')
    })

    if (!existsTailwindPlugin()) {
      await import('@tailwindcss/vite').then(r => addVitePlugin(r.default()))
    }
  }
  else {
    nuxt.options.postcss ??= { plugins: {}, order: [] }
    nuxt.options.postcss.plugins ??= {}

    if (!nuxt.options.postcss.plugins['@tailwindcss/postcss']) {
      nuxt.options.postcss.plugins['@tailwindcss/postcss'] = {}
    }
  }
}

export type UnwatchStorageMount = () => Promise<void> | void
type WatchEvent = 'update' | 'remove'
type WatchCallback = (event: WatchEvent, key: string) => void

export async function watchStorageMount(storage: Storage, mountName: string, onChange: WatchCallback): Promise<UnwatchStorageMount> {
  const mountKey = normalizeBaseKey(mountName)
  const mount = storage.getMount(mountKey)
  if (!mount || normalizeBaseKey(mount.base) !== mountKey || !mount.driver?.watch)
    return () => {}

  const unwatch = await mount.driver.watch((event: WatchEvent, key: string) => {
    const fullKey = key.startsWith(mountKey) ? key : `${mountKey}${key}`
    onChange(event, normalizeKey(fullKey))
  })
  return unwatch ?? (() => {})
}

export async function resolveNuxtModule (base: string, paths: string[]): Promise<string[]> {
  const resolved: string[] = []
  const resolver = createResolver(base)

  for (const path of paths) {
    if (path.startsWith(base)) {
      resolved.push(path.split('/index.ts')[0]!)
      continue
    }
    const resolvedPath = await resolver.resolvePath(path)
    const dir = parseNodeModulePath(resolvedPath).dir
    if (dir) {
      resolved.push(dir)
      continue
    }
    const index = resolvedPath.lastIndexOf(path)
    resolved.push(index === -1 ? dirname(resolvedPath) : resolvedPath.slice(0, index + path.length))
  }

  return resolved
}

function createPortalProperties (sourceValue: any, options: NuxtOptions, paths: string[]) {
  let sharedValue = sourceValue

  for (const path of paths) {
    const segments = path.split('.')
    const key = segments.pop()!
    let parent: Record<string, any> = options

    while (segments.length) {
      const key = segments.shift()!
      parent = parent[key] ||= {}
    }

    delete parent[key]

    Object.defineProperties(parent, {
      [key]: {
        configurable: true,
        enumerable: true,
        get: () => sharedValue,
        set (value) {
          sharedValue = value
        },
      },
    })
  }
}

const open = <T extends Component>(id: symbol, props?: ComponentProps<T>): OpenedOverlay<T> => {
  const overlay = getOverlay(id)

  // If props are provided, merge them with the original props, otherwise use the original props
  if (props) {
    overlay.props = { ...overlay.originalProps, ...props }
  } else {
    overlay.props = { ...overlay.originalProps }
  }

  overlay.isOpen = true
  overlay.isMounted = true
  const result = new Promise<any>(resolve => overlay.resolvePromise = resolve)

  return Object.assign(result, {
    id,
    isMounted: overlay.isMounted,
    isOpen: overlay.isOpen,
    result
  })
}

